def solve(highest_temperature, heart_rate, atrial_fibrillation, chf_severity, cns_severity, gi_hepatic_severity, precipitant_present):
    # Step 1: temperature_score - Assign a score based on the highest body temperature measured in Celsius.
    if highest_temperature <= 37.1:
        temperature_score = 0
    elif 37.2 <= highest_temperature <= 37.7:
        temperature_score = 5
    elif 37.8 <= highest_temperature <= 38.2:
        temperature_score = 10
    elif 38.3 <= highest_temperature <= 38.8:
        temperature_score = 15
    elif 38.9 <= highest_temperature <= 39.4:
        temperature_score = 20
    elif 39.5 <= highest_temperature <= 39.9:
        temperature_score = 25
    else:  # temperature >= 40.0
        temperature_score = 30
    yield {
        "step_name": "temperature_score",
        "step_description": "Assign a score based on the highest body temperature measured in Celsius.",
        "step_result": temperature_score,
        "unit": None
    }

    # Step 2: tachycardia_score - Assign a score based on the heart rate in beats per minute.
    if heart_rate < 90:
        tachycardia_score = 0
    elif 90 <= heart_rate <= 109:
        tachycardia_score = 5
    elif 110 <= heart_rate <= 119:
        tachycardia_score = 10
    elif 120 <= heart_rate <= 129:
        tachycardia_score = 15
    elif 130 <= heart_rate <= 139:
        tachycardia_score = 20
    else:  # heart_rate >= 140
        tachycardia_score = 25
    yield {
        "step_name": "tachycardia_score",
        "step_description": "Assign a score based on the heart rate in beats per minute.",
        "step_result": tachycardia_score,
        "unit": None
    }

    # Step 3: atrial_fibrillation_score - Assign a score based on the presence or absence of atrial fibrillation.
    atrial_fibrillation_score = 10 if atrial_fibrillation else 0
    yield {
        "step_name": "atrial_fibrillation_score",
        "step_description": "Assign a score based on the presence or absence of atrial fibrillation.",
        "step_result": atrial_fibrillation_score,
        "unit": None
    }

    # Step 4: congestive_heart_failure_score - Assign a score based on the severity of congestive heart failure.
    chf_map = {'none': 0, 'mild': 5, 'moderate': 10, 'severe': 15}
    chf_score = chf_map.get(chf_severity, 0)
    yield {
        "step_name": "congestive_heart_failure_score",
        "step_description": "Assign a score based on the severity of congestive heart failure.",
        "step_result": chf_score,
        "unit": None
    }

    # Step 5: cns_dysfunction_score - Assign a score based on the severity of central nervous system involvement.
    cns_map = {'none': 0, 'mild': 10, 'moderate': 20, 'severe': 30}
    cns_score = cns_map.get(cns_severity, 0)
    yield {
        "step_name": "cns_dysfunction_score",
        "step_description": "Assign a score based on the severity of central nervous system involvement.",
        "step_result": cns_score,
        "unit": None
    }

    # Step 6: gi_hepatic_dysfunction_score - Assign a score based on the severity of gastrointestinal or hepatic dysfunction.
    gi_hepatic_map = {'none': 0, 'moderate': 10, 'severe': 20}
    gi_hepatic_score = gi_hepatic_map.get(gi_hepatic_severity, 0)
    yield {
        "step_name": "gi_hepatic_dysfunction_score",
        "step_description": "Assign a score based on the severity of gastrointestinal or hepatic dysfunction.",
        "step_result": gi_hepatic_score,
        "unit": None
    }

    # Step 7: precipitant_score - Assign a score based on the presence or absence of a precipitating factor.
    precipitant_score = 10 if precipitant_present else 0
    yield {
        "step_name": "precipitant_score",
        "step_description": "Assign a score based on the presence or absence of a precipitating factor.",
        "step_result": precipitant_score,
        "unit": None
    }

    # Step 8: total_bwps_score - Sum all individual category scores to compute the total BWPS score.
    total_score = (temperature_score + tachycardia_score + atrial_fibrillation_score +
                   chf_score + cns_score + gi_hepatic_score + precipitant_score)
    yield {
        "step_name": "total_bwps_score",
        "step_description": "Sum all individual category scores to compute the total BWPS score.",
        "step_result": total_score,
        "unit": None
    }

    return total_score
